"""
MKT Original Layer — Ezekiel chapters 36–38
Run: python3 scripts/zc-original-ezekiel-36-38-fill.py

Three of the most theologically dense chapters in Ezekiel:

Ch 36: The New Heart and New Spirit oracle — YHWH acts for the sake of his holy
  name, not Israel's merit. Key terms: chilel/qiddesh (profane/sanctify), shem
  (name), niddah/tum'ah (impurity), zaraq (sprinkle, H2236), lev basar vs lev
  avanim (heart of flesh vs stone), ruach/Spirit.

Ch 37: The Valley of Dry Bones — national resurrection as enacted prophecy.
  Ruach (H7307) appears 9 times in vv.1-14. Two-sticks oracle (37:15-28):
  reunification of Judah and Ephraim under one Davidic shepherd.

Ch 38: Gog of Magog (first oracle) — eschatological adversary; coalition of
  nations from north and south; divine fury vocabulary (af, chemah, qin'ah);
  the cosmic shaking; b'acharit hashanim (in the latter years).

Note: Ezekiel 36:26 already has an entry (new heart/spirit verse). merge_comm
  will not overwrite it.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZK_ORIG = {
  "36": {
    "1": "<p><strong>veatah ben-adam hinabbe el-harei yisrael</strong> ('son of man, prophesy to the mountains of Israel'): the mountains of Israel are addressed directly as the recipients of the restoration oracle. Ch 36 opens as the counterpart to the ch 6 judgment oracle that was also addressed to the mountains (6:2-3). The mountains that received the sword, famine, and plague of judgment now receive the promise of life and flourishing.</p>",
    "2": "<p><strong>yaan amar ha'oyev aleichem heach bamot olam</strong> ('the enemy has said of you: Aha! the ancient heights have become our possession'): Edom (from ch 35) and other enemies have exulted over Israel's desolated heights. <em>bamot olam</em> ('ancient/eternal high places') — the mountains Israel has inhabited since the patriarchal era. The enemy's gloating ('heach!' = a cry of malicious satisfaction) is the theological occasion for YHWH's response.</p>",
    "3": "<p><strong>yaan yaan shomate</strong> ('because — yes, because you are desolate'): the doubled <em>yaan</em> for emphasis — a construction that intensifies the causal connection. The desolation of the land (from the Babylonian conquest) is real and acknowledged; YHWH's oracle does not minimize it. But the enemy's contemptuous seizure and mockery of Israel's land becomes an affront to YHWH that generates the restoration.</p>",
    "4": "<p>The comprehensive address: mountains, hills, ravines, valleys, desolate wastes, abandoned cities — the whole topography of ruined Judah is addressed. The oracle covers every part of the landscape, leaving no part of the land excluded from the restoration promise. The specificity of the address (seven categories of terrain) emphasizes the thoroughness of the coming transformation.</p>",
    "5": "<p><strong>beeesh qin'ati dibbarti</strong> ('in the fire of my jealousy I have spoken'): <em>qin'ah</em> (H7068, jealousy/zeal) — YHWH's jealousy is not a weakness but an expression of covenant fidelity. The same <em>qin'ah</em> that executed judgment on Israel for idolatry (5:13; 8:3) now burns against the nations that have seized the covenant land. <em>yaan shim'chat kal-levav uveuzat naphesh legarsh otah</em> — 'because of wholehearted joy and bitter contempt with which they made my land their possession': the malice and contempt (not merely opportunism) of the nations' action triggers the jealous response.</p>",
    "6": "<p><strong>davari al-admat yisrael</strong> ('speak about the land of Israel'): YHWH's jealousy for his land — the land is inseparably connected to his covenant identity. The nations' contempt for Israel is simultaneously contempt for YHWH, since the land is his. This theological point drives the restoration: YHWH acts to vindicate his own reputation, not merely to restore Israel out of sentiment.</p>",
    "7": "<p><strong>im-lo haggoyim asher-lachem misaviv hemah yesu kalimatam</strong> ('the nations around you will themselves bear their disgrace'): the reversal-formula — those who shamed Israel will be shamed. The same vocabulary (<em>kalimah</em>, H3639, shame/disgrace) applied to Israel in exile is redirected to the surrounding nations. YHWH's oath (<em>nesa yadi</em>, 'I have raised my hand') formalizes the reversal.</p>",
    "8": "<p><strong>veaitem titenu anpechem uvliyitem piriechem</strong> ('you mountains will put forth your branches and bear your fruit for my people Israel'): the mountains addressed as living entities bearing fruit — the same personification as in ch 6 (where they were addressed as recipients of judgment). The mountains are commanded to participate in the restoration: <em>ki qerovim lavo</em> ('for they are soon to come'). The returning exiles are the 'soon' — the restoration is not distant.</p>",
    "9": "<p><strong>ki hineni eleichem upeniti aleichem venirashtem venigraztem</strong> ('I will turn to you and you will be tilled and sown'): <em>panah el</em> (H6437, to turn toward/face toward) — YHWH's face turning toward the mountains as the active agent of restoration. Tilling and sowing are the signs of cultivated settlement versus the desolation of abandoned fields. The agricultural renewal is the sign of human return.</p>",
    "10": "<p><strong>vehirbeiti aleichem adam</strong> ('I will multiply people on you'): the reversal of the depopulation caused by exile, sword, and famine. <strong>venishvu hecheharim uhivnyu habamot</strong> ('the ruined cities will be inhabited and the waste places built'): <em>charubot</em> (H2723, ruins/waste places) repopulated — the archaeological landscape of conquest reversed by divine restoration.</p>",
    "11": "<p><strong>vehirbeiti aleichem adam uvehemah verebu veparu</strong> ('I will multiply people and animals on you; they will increase and be fruitful'): the Genesis 1:28 fertility mandate (<em>peru urevu</em>, 'be fruitful and multiply') applied to the restored land. The restoration recapitulates creation: the fruitfulness that was interrupted by the exile-curse is restarted by YHWH's direct action. <strong>kaqdemonichem asiti</strong> ('I will make you as in your former state'): restoration to pre-exile conditions, but — as subsequent verses clarify — actually surpassing the former state.</p>",
    "12": "<p><strong>veholachti aleichem adam et-ami yisrael</strong> ('I will bring my people Israel on you'): the possessive construction — <em>ami yisrael</em> ('my people Israel') emphasizes the covenant relationship that the exile appeared to have dissolved. <strong>veyerishuch</strong> ('they will possess you'): the land-possession verb (<em>yaresh</em>, H3423) that constitutes the fulfillment of the ancestral promises from Num 13-14 through Deut 30:5.</p>",
    "13": "<p><strong>koh amar adonai YHWH yaan yomerim lach ochelet adam at</strong> ('because they say of you: you devour human beings'): the accusation against the land — that it consumes its inhabitants (a pagan understanding of why successive peoples were expelled from Canaan). <em>ocheleth adam</em> — the land as a man-eater, like the slanderous report of the spies (Num 13:32: 'the land devours its inhabitants'). YHWH addresses and denies this accusation about his own land.</p>",
    "14": "<p><strong>lachen adam lo-tocheeli od uggoyech lo-teshakeli od</strong> ('you will no longer devour human beings and no longer bereave your nation'): YHWH's direct rebuttal of the accusation — the land will not 'eat' its inhabitants. The implied theology: the expulsions and deaths were not the land's inherent hostility but YHWH's specific judgments that have now run their course. The land's character is restored alongside the people's restoration.</p>",
    "15": "<p><strong>velo-ashmi'a elayich od klimat haggoyim</strong> ('I will no longer cause you to hear the insults of the nations'): the end of the international shame that accompanied exile. <em>cherpath ammim lo-tis'i od</em> ('you will no longer bear the reproach of the peoples'): <em>cherpah</em> (H2781, reproach/shame) — the same shame that Job mourned and the Psalms cry out against. The restoration removes not just the physical desolation but the shame that accompanied it.</p>",
    "16": "<p>The shift to the theological explanation of exile (vv.16-21) — the 'because' section before the 'therefore' restoration. YHWH speaks directly: the exile happened because of Israel's conduct and deeds.</p>",
    "17": "<p><strong>ben-adam beit yisrael yoshvim al-admatam vayetamu'u otah bedarkam uvealilotam</strong> ('son of man, when the house of Israel dwelt in their own land, they defiled it by their ways and their deeds'): the historical summary of why the land was given over. <strong>ketumah haniddah hayetah darkam lefanai</strong> ('their way was before me like the impurity of a menstruous woman'): <em>niddah</em> (H5079, menstrual impurity/isolation period) — the strongest cultic impurity language in the Levitical system (Lev 15:19-30). Israel's conduct was ritually defiling to the land itself. The land as covenant space shared YHWH's holiness and could not tolerate Israel's conduct.</p>",
    "18": "<p><strong>vaeshpoch chamati aleichem</strong> ('I poured out my wrath on them'): <em>shaphach chemah</em> — the standard Ezekielian phrase for divine wrath-execution. <strong>al-hadam asher-shapechu al-haaretz</strong> ('for the blood they shed on the land'): blood-pollution of the land (Num 35:33: blood pollutes the land) — the legal basis for the exile. The land could not tolerate innocent blood; YHWH executed the legal requirement of expulsion.</p>",
    "19": "<p><strong>vaeputzem baggoyim vayyizaru baarasot</strong> ('I scattered them among the nations and they were dispersed through the countries'): the Deuteronomic curse executed (Deut 4:27; 28:64). The scatter-verb <em>putz</em> (H6327) and <em>zarah</em> (H2219, winnow/scatter) — both agricultural metaphors for the violent dispersal of a community.</p>",
    "20": "<p><strong>vayavo el-haggoyim asher-bau sham vayehalelu et-shem qodshi</strong> ('when they came to the nations where they went, they profaned my holy name'): the remarkable claim — Israel's continued existence as a scattered people was itself a profanation of YHWH's name. <em>chilel shem qodshi</em> (H2490 + H8034 + H6944, profane holy name) — the nations observed exiled Israel and concluded 'YHWH could not protect his people.' The exile that was meant to honor YHWH's justice was being interpreted by the nations as YHWH's weakness or failure.</p>",
    "21": "<p><strong>vaechamal al-shem qodshi</strong> ('I had concern/compassion for my holy name'): <em>chamal</em> (H2550, spare/have compassion/be concerned for) — YHWH's motivation for the restoration is explicitly his concern for his own name's reputation, not Israel's merit. The restoration is an act of theological self-vindication. This is the most theologically direct statement of YHWH's motivation in the entire OT: the nations were getting the wrong message; YHWH acts to correct it.</p>",
    "22": "<p><strong>lachen emor leveit yisrael koh amar adonai YHWH lo lemankhem ani oseh beit yisrael ki im-leshmi haqadosh</strong> ('therefore say to Israel: not for your sake am I acting, house of Israel, but for my holy name'): the explicit statement of YHWH's motivation — emphatically <em>not</em> for Israel's sake but for his own name. <em>lo lemankhem</em> is placed first for maximum emphasis. This is the theological anti-sentimentalism of the OT: the restoration is not sentimental return because YHWH loves Israel; it is YHWH acting to vindicate his own reputation among the nations. Israel is the vehicle, not the ultimate purpose.</p>",
    "23": "<p><strong>veqiddashti et-shemi hagadol hamechullal baggoyim</strong> ('I will sanctify my great name which has been profaned among the nations'): <em>qiddesh</em> (H6942, sanctify/hallow) versus <em>chilel</em> (H2490, profane) — the key antithesis of this oracle. <strong>veyadu haggoyim ki-ani YHWH</strong>: the recognition formula applied to the nations — the restoration of Israel serves YHWH's self-disclosure to the entire world. <strong>behiqadshi bachem leeyneichem</strong> ('when I show myself holy in you before their eyes'): YHWH's holiness displayed in Israel's restoration functions as a sermon to the nations about who YHWH is.</p>",
    "24": "<p><strong>velaqachti etchem min-haggoyim</strong> ('I will take you from the nations'): the second Exodus vocabulary — <em>laqach</em> (take/gather) from the nations parallels the first Exodus from Egypt. <strong>uqibatzti etchem mikol-haaratzot</strong> ('and gather you from all the lands'): the ingathering of the scattered, reversing the diaspora of v.19. The return from Babylon is the near fulfillment; the ultimate fulfillment awaits the complete ingathering.</p>",
    "25": "<p><strong>vezaraqti aleichem mayim tehorim uteharthem</strong> ('I will sprinkle clean water on you and you will be clean'): <em>zaraq</em> (H2236, sprinkle — the priestly sprinkling verb used in sacrificial purification, Lev 1:5; Num 19:13-20; the red heifer waters). The purification of the restored people is accomplished by YHWH himself performing the priestly act of sprinkling. <strong>mikol-tum'oteichem umikol-gilluleichem ataher etchem</strong> ('from all your impurities and from all your idols I will cleanse you'): comprehensive cleansing covering both ritual impurity (<em>tum'ah</em>) and moral/idolatrous pollution (<em>gillulim</em>).</p>",
    "27": "<p><strong>vet-ruchi eten beqirbechem</strong> ('I will put my Spirit within you'): the interior dimension of the new covenant — the Spirit placed <em>beqerev</em> (within, in the midst of). <em>ruach</em> (H7307, spirit/breath/wind). The new heart of v.26 receives the animating Spirit of v.27. <strong>veeth-chuqqotai tishmeiru vaasitem</strong> ('I will cause you to walk in my statutes and you will keep my ordinances and do them'): the Spirit's work is specifically defined as enabling Torah-observance. The failure of the old covenant (Israel could not keep the commandments) is addressed by the interior gift of the Spirit who works obedience from within.</p>",
    "28": "<p><strong>veyashavtem baaretz asher natati laavoteichem</strong> ('you will dwell in the land I gave to your fathers'): the land-covenant renewed. <strong>vihyitem li le'am vaani ehyeh lachem le'Elohim</strong> ('you will be my people and I will be your God'): the covenant formula (H1961 + H5971 + H430) — the most fundamental statement of covenant relationship in the OT (from Lev 26:12 through Jer 31:33; Ezek 11:20; 14:11; Rev 21:3). The covenant threatened and dissolved by the exile is reconstituted under the new heart/Spirit arrangement.</p>",
    "29": "<p><strong>vehoshati mechal-tum'oteichem</strong> ('I will save you from all your uncleanness'): <em>yasha</em> (H3467, save) — the salvation vocabulary applied to the cleansing from impurity. Salvation and purification are linked: the same act that restores the covenant relationship removes the defilement that interrupted it. <strong>veqarati el-hadagan vehirbiti oto</strong> ('I will call to the grain and multiply it'): YHWH summoning agricultural abundance — the reversal of the covenant curses of famine and blight.</p>",
    "30": "<p>The restoration of agricultural abundance — fruit, grain, the end of famine. The reversal of the curses of Lev 26 and Deut 28: the land will produce its fruit so that Israel will no longer suffer the disgrace of famine among the nations. The nations that noted Israel's famine as evidence of divine abandonment will see its reversal as evidence of divine restoration.</p>",
    "31": "<p><strong>uzchartem et-darkeichem hara'im</strong> ('you will remember your evil ways'): the remembrance of sin as part of the restoration, not as pre-condition but as consequence. Israel will remember its evil ways and deeds and loathe itself (<em>qot</em>, H6962, feel loathing/disgust) in its own sight. Genuine restoration produces self-abasement, not self-satisfaction. <strong>lo-lemaanchem</strong> again — 'not for your sake': the restoration does not generate pride in Israel but self-examination and shame.</p>",
    "32": "<p><strong>lo lemankhem ani oseh</strong> ('it is not for your sake that I am acting'): the formula repeated from v.22 — the divine motivation is reasserted at the conclusion of the restoration oracle. The repetition brackets the entire oracle of vv.22-32 with the same theological claim. YHWH acts for his own name; Israel is the beneficiary but not the cause. <strong>boshtem vekhalmuni</strong> ('be ashamed and humiliated'): shame as the appropriate response to undeserved grace — the restoration should produce not pride but deep shame at the contrast between what Israel deserves and what YHWH gives.</p>",
    "33": "<p><strong>koh amar adonai YHWH beyom tahhari etchem miqqol avonoteichem</strong> ('on the day I cleanse you from all your iniquities'): the day of cleansing as the trigger for the restoration of the cities. YHWH's act of moral cleansing and the act of urban reconstruction are simultaneous — the inner renewal produces the outer restoration. The land's desolation was a consequence of Israel's moral defilement; cleansing produces rebuilding.</p>",
    "34": "<p><strong>vehaadamah hanneshamah teaved tachath asher haytah shemamah le-eynei kol avar</strong> ('the desolate land will be tilled instead of being a desolation in the sight of all who pass by'): the public nature of the restoration — those who passed by and saw the desolation as evidence of divine abandonment will see the tilled land as evidence of divine restoration. The restoration is a visible theological statement to the watching world.</p>",
    "35": "<p><strong>vaomru haaretz halezut hayeta keGan-Eden</strong> ('and they will say: this land that was desolate has become like the garden of Eden'): <em>Gan-Eden</em> (the garden of Eden) as the highest possible standard of agricultural beauty and fertility. The restored land compared to Eden is the ultimate statement of what YHWH intends for the covenant land — not merely pre-exile normalcy but Edenic abundance. The garden destroyed by the Serpent and closed by cherubim is the type for the restoration.</p>",
    "36": "<p><strong>veyadu haggoyim ki ani YHWH</strong> ('the nations will know that I am the LORD'): the recognition formula on the lips of the nations — their observation of Eden-like Israel will produce knowledge of YHWH. The nations learn who YHWH is not through theological argument but through observable transformation of Israel's land. <strong>baniti hacharubot natati nezerot</strong> ('I YHWH have rebuilt the ruined places and replanted the desolate areas'): YHWH as builder and farmer — the divine craftsman who rebuilds what was demolished and the divine gardener who replants what was uprooted.</p>",
    "37": "<p>The parabolic comparison: Israel's small population (like a few sheep in Jerusalem's pasture, before the exile) versus the restored great flocks filling the cities. The restored cities compared to the festive sheep-market in Jerusalem before major feasts — dense, noisy, full of life. The desolation reversed into abundance that exceeds the former state.</p>",
    "38": "<p><strong>veyadu ki-ani YHWH</strong>: the chapter closes with the recognition formula for the seventh and final time in ch 36. The seven-fold repetition of <em>yadu ki-ani YHWH</em> in this chapter is structural: the entire oracle is oriented toward the epistemological outcome. Every act of restoration — cleansing, Spirit-giving, agricultural abundance, land rebuilding — serves this single end: that YHWH will be known as YHWH.</p>"
  },
  "37": {
    "1": "<p><strong>haytah alai yad-YHWH vayotzieni veruach YHWH</strong> ('the hand of the LORD was on me; the Spirit of the LORD carried me out'): the inaugural vision formula (cf. 1:1; 3:14,22; 8:1) — the characteristic language of Ezekiel's visionary transport. <em>ruach YHWH</em> (H7307, Spirit of the LORD) — the Spirit appears 9 times in vv.1-14, bracketing the entire vision. <strong>vayenicheni betouch habiq'a</strong> ('and set me down in the middle of the valley'): the same <em>biq'ah</em> (H1237, valley/plain) as 3:22 — the Chebar plain. The vision is located in the same space as Ezekiel's original commissioning vision.</p>",
    "2": "<p><strong>vehi melea atzamot</strong> ('it was full of bones'): the valley of dry bones — Israel as the dead scattered across a battlefield. <strong>vaavir oti aleichem saviv saviv</strong> ('he led me around them on all sides'): the prophetic tour of the battlefield — a complete survey of the extent of the death before the resurrection is proclaimed. The careful observation of the death prepares the prophet and the reader for the magnitude of what follows.</p>",
    "3": "<p><strong>vayomer elai ben-adam hatichyena haatzamot haeleh</strong> ('he said to me: son of man, can these bones live?'): the central question of the vision — posed as a genuine question to the prophet, not as a rhetorical certainty. <strong>vaomar adonai YHWH atah yadatah</strong> ('I said: Lord GOD, you know'): Ezekiel's response is the perfectly calibrated prophetic humility — he does not claim to know what is outside his sight. The answer to the question 'can these bones live?' is known only by YHWH. The prophetic posture of epistemic dependence is the right posture before the divine possibility of resurrection.</p>",
    "4": "<p><strong>vayomer elai hinabbe al-haatzamot haeleh</strong> ('he said to me: prophesy over these bones'): the command to prophesy to the dead — an act that demonstrates that prophetic speech participates in the divine creative act. The prophet speaks into non-existence and calls it into existence. <em>shim'u devar YHWH</em> ('hear the word of the LORD'): even the dead bones are commanded to hear — the word of YHWH has power that bypasses the apparent impossibility.</p>",
    "5": "<p><strong>koh amar adonai YHWH laatzamot haeleh</strong> ('thus says the Lord GOD to these bones'): YHWH speaking directly to dead bones — the oracle addressed to the non-living is the most radical deployment of prophetic speech in the OT. <strong>hineh ani mebi bachem ruach vicheeytem</strong> ('I will cause breath to enter you and you will live'): <em>ruach</em> (H7307, breath/wind/spirit) — the same word as in Gen 2:7 where YHWH breathes into Adam's nostrils. The valley of dry bones is a second creation, recapitulating the first.</p>",
    "6": "<p><strong>venatatti aleichem gidin vehaaleti aleichem basar</strong> ('I will put sinews on you and bring flesh on you'): the anatomical sequence — sinews (H1517, gidin), flesh (H1320, basar), skin (H5785, or). The physiological reconstitution of a human being in precise order: the structural framework (bones) → sinews (tendons binding bones) → flesh (muscle) → skin (covering). The reversal of decomposition. <strong>venatatif lachem ruach vicheeytem</strong>: the breath/spirit given last — structure without spirit is still a corpse; the order matters.</p>",
    "7": "<p><strong>venibbeti kaasher tzuviti vatashav ruach vetiqqerenah atzamot atzem el-atzmo</strong> ('as I prophesied there was a noise, and a rattling, and the bones came together, bone to bone'): the great noise (<em>qol</em>, sound) and the rattling (<em>rash</em>, H7494, earthquake/rattling/commotion) of bones assembling — the auditory experience of resurrection. <em>atzem el-atzmo</em> ('bone to its bone') — each bone finding its anatomical counterpart: precise, purposeful assembly. The chaos of the battlefield is reorganized into living bodies.</p>",
    "8": "<p><strong>veraiti vehinneh aleichem gidin uvasar alah vatiqra aleichem or</strong> ('I looked, and sinews and flesh appeared on them and skin covered them over'): the visible sequence of reconstitution — the prophet watches it happen layer by layer. <strong>veruach ayin bahem</strong> ('but there was no breath/spirit in them'): the corpses are anatomically complete but not yet living — a crucial observation. Physical reconstitution alone does not constitute life; the Spirit must be separately given. The two-stage resurrection emphasizes the independence of the Spirit's gift.</p>",
    "9": "<p><strong>vayomer elai hinabbe el-haruach</strong> ('he said to me: prophesy to the breath'): the second prophetic command — now to the <em>ruach</em> itself. <strong>koh amar adonai YHWH merarba ruchot boi haruach</strong> ('thus says the Lord GOD: come from the four winds, O breath'): <em>me-arba ruchot</em> ('from the four winds') — north, south, east, west — the breath/spirit gathered from the entire cosmos to fill the reconstituted bodies. The cosmic gathering of the Spirit parallels the cosmic gathering of the exiles in v.21. <strong>ufchi baharugim haeleh viyichyu</strong> ('breathe into these slain that they may live'): the exact parallel to Gen 2:7 (<em>vayipach beapav nishmat chayyim</em>).</p>",
    "10": "<p><strong>vatavo bahem haruach vayyichyu vayyiqumu al-ragleichem</strong> ('the breath entered them and they lived and stood on their feet'): the sequence of resurrection: breath enters → they lived (<em>chayyah</em>, H2421) → stood on their feet. <strong>chayil gadol meod meod</strong> ('a very, very great army'): from dead bones scattered on the battlefield to a vast living army. The hyperbolic <em>meod meod</em> ('exceedingly very great') emphasizes the completeness of the reversal — not merely survival but abundant vitality.</p>",
    "11": "<p><strong>ben-adam haatzamot haeleh kol-beit yisrael hemah</strong> ('son of man, these bones are the whole house of Israel'): the divine interpretation of the vision — the bones are not a future military event but present-tense Israel in exile. <strong>hinnam omrim yaveshu atzmoteinu veaveda tikvatenu</strong> ('they are saying: our bones are dried up and our hope is perished'): the national lament: <em>tikvah</em> (H8615, hope/cord/expectation) — the same word as in Job 17:15 (where can my hope be found?) and Jer 29:11 (plans for a future and a hope). The exiles' despair is that hope itself has been destroyed — not merely delayed but eliminated.</p>",
    "12": "<p><strong>lachen hinabbe veamarta aleichem koh amar adonai YHWH hineh ani potei'ach et-qivrotechem</strong> ('therefore prophesy and say to them: thus says the Lord GOD: I will open your graves'): the direct application of the vision to the national situation — YHWH will open graves and bring out (<em>alah</em>, H5927, cause to come up) the people from their graves. <em>qever</em> (H6913, grave/tomb) — exile as a kind of death-state. The return from exile is analogized to resurrection from the grave. <strong>vahaveti etchem el-admat yisrael</strong>: the land of Israel as the destination of the resurrection.</p>",
    "13": "<p><strong>veyidattem ki-ani YHWH befotchi et-qivrotechem</strong> ('you will know that I am the LORD when I open your graves'): the recognition formula attached to the resurrection act — the knowledge of YHWH is the purpose of the resurrection. The resurrection event is epistemological: it teaches Israel who YHWH is in a way that nothing else could. <strong>uvehaaloti etchem miqivrotechem ami</strong> ('and when I bring you up from your graves, my people'): the covenant designation <em>ami</em> ('my people') — restored at the moment of resurrection. The resurrection constitutes the covenantal relationship.</p>",
    "14": "<p><strong>venatatti ruchi bachem vicheeytem</strong> ('I will put my Spirit in you and you will live'): the synthesis of ch 36:27 and the valley vision — the Spirit given internally (36:27) is the breath that animates the dry bones (37:5-10). The two oracles are the same promise from different angles: the outward vision (dry bones to living army) and the inward promise (new heart, Spirit within). <strong>vehinnachti etchem al-admatechem</strong> ('I will put you down on your own land'): the final and ultimate settling — not temporary residence but permanent establishment (<em>nuach</em>, H5117, rest/settle permanently).</p>",
    "15": "<p>The new unit: two-sticks oracle (vv.15-28). The visual demonstration is different from the valley vision: instead of a landscape transformation, it is a hand-held enacted sign. Ezekiel holds two sticks, one for Judah and one for Ephraim/Joseph, and the two become one in his hand.</p>",
    "16": "<p><strong>et le-Yehudah</strong> ('for Judah'): <em>etz</em> (H6086, tree/stick/wood) — a stick of writing material (a writing tablet or rod). <strong>ulveit Yisrael chaveirav</strong> ('for the house of Israel his companions') — the northern kingdom's associated tribes. <strong>veet-et Yosef asher beyad Efrayim</strong> ('the stick of Joseph which is in Ephraim's hand'): the dominant northern tribe gives its name to the Northern Kingdom. The two sticks represent the 931 BCE division of the united monarchy (1 Kgs 12) which had become permanent national separation.</p>",
    "17": "<p><strong>veqarev otam echad el-echad lecha leetz echad vehayu leachad beyadechu</strong> ('join them together into one stick, and they will become one in your hand'): the enacted prophecy — the physical joining of two sticks in the prophet's hand demonstrates the political reunification of the divided kingdom. <em>leetz echad</em> ('to become one stick') — the oneness is specified: not merely cooperation but unity. The acted sign communicates what Israel's political history said was impossible.</p>",
    "18": "<p>The disciples' question: 'Will you not tell us what you mean by these?' — the acted prophecy requires interpretation, and the disciples recognize its interpretive demand. Ezekiel's sign-acts consistently create interpretive questions that provide the occasion for the divine explanation (cf. 12:9; 24:19). The question is part of the pedagogical design.</p>",
    "19": "<p><strong>hineni loqei'ach et-etz Yosef asher beyad Efrayim</strong> ('I am taking the stick of Joseph which is in Ephraim's hand'): YHWH's own description of the sign-act, identifying with what the prophet performs. <strong>vesamti otam alav et-etz Yehudah vaasitim leetz echad</strong> ('and I will put them together — the stick of Judah — and they will become one stick'): the political reunification is explicitly YHWH's action. The political possibility of the sign is grounded in divine sovereign ability, not human political process.</p>",
    "20": "<p>The sticks held visibly in the prophet's hand — the public enactment of the oracle. The acted prophecy is communal: the sign is performed before the eyes of the exilic community, making the promise concrete and memorable. Even in Babylon, the exiles are watching a visual demonstration of their promised future.</p>",
    "21": "<p><strong>velaqachti et-benei yisrael mibbein haggoyim asher halchu sham</strong> ('I will take the Israelites from among the nations where they have gone'): the gathering formula — <em>laqach</em> (take/gather) from among the nations. The second Exodus pattern: just as YHWH took Israel out of Egypt, he will take the scattered exiles from among the nations. <strong>veqibatzti otam missaviv</strong> ('I will gather them from all around'): the comprehensive gathering of diaspora from every direction.</p>",
    "22": "<p><strong>vaasiti otam legoy echad baaretz beharei yisrael ulemelech echad yihyeh lahem lemelech lekulam</strong> ('I will make them one nation in the land on the mountains of Israel, and one king will be king over them all'): the political outcome of the restoration — <em>goy echad</em> (one nation) with <em>melech echad</em> (one king). The division of the Solomonic monarchy is permanently reversed. <strong>velo yihu od lishnei goyim</strong> ('they will no longer be two nations'): the permanent end of the north-south division. The two-kingdoms situation, which had persisted for four centuries, will not recur.</p>",
    "23": "<p><strong>velo yitamme'u od begilluleihem</strong> ('they will no longer defile themselves with their idols'): the spiritual component of the restoration — freedom from idolatry. <strong>vehoshi'a otam miqqol moshevoteihem asher chatu bahem</strong> ('I will save them from all their apostasies'): <em>yasha</em> (H3467, save) — salvation from the specific sin of apostasy, not merely from external enemies. <strong>vetihartem vehayu li le'am</strong> ('I will cleanse them and they will be my people'): the covenant formula applied to the spiritually restored community.</p>",
    "24": "<p><strong>veabdi David melech aleichem</strong> ('my servant David will be king over them'): the Davidic covenant renewed — the promised Davidic king who will shepherd the unified nation. <em>David</em> here is not the historical David (who died c.970 BCE) but the eschatological Davidic descendant, the anointed king promised in 2 Sam 7 and Ps 2; 89; 110. <strong>veroeh echad yihyeh lechulam</strong> ('one shepherd will be for all of them'): the shepherd-king of ch 34 is the Davidic descendant. <strong>uvechuqqotai yelekhu</strong> ('they will walk in my statutes'): the Spirit-enabled Torah-observance of 36:27 finds its political correlate in the Davidic ruler.</p>",
    "25": "<p><strong>veyashvu al-haaretz asher natati leabdi leyaaqov asher yashvu vah avoteichem</strong> ('they will live in the land I gave to my servant Jacob — the land where your fathers lived'): the patriarchal land-grant renewed through Davidic-covenant language. The triple covenant connection: the land given to Jacob (patriarchal), the king from David (Davidic), and the Spirit-given Torah obedience (new covenant). <strong>venasi lahem le'olam</strong> ('a prince will be over them forever'): <em>nasi le'olam</em> — the eternal prince. The Davidic ruler's permanence answers the revolving-door kingship of Israel's historical kings.</p>",
    "26": "<p><strong>vekarati lahem berit shalom</strong> ('I will make a covenant of peace with them'): <em>berit shalom</em> (H1285 + H7965, covenant of peace) — the fullest form of the new covenant promise (also Num 25:12; Isa 54:10). <strong>berit olam yihyeh otam</strong> ('it will be an eternal covenant with them'): <em>berit olam</em> — the permanent covenant that cannot be broken. The covenant of peace combines political security, agricultural abundance, and divine presence. <strong>untetim vehirbeitem venatatiti et-miqdashi betocham le'olam</strong> ('I will increase them and put my sanctuary in their midst forever'): the sanctuary — YHWH's permanent dwelling in the midst of the restored unified nation.</p>",
    "27": "<p><strong>vehayah mishkani aleichem</strong> ('my dwelling will be over them'): <em>mishkan</em> (H4908, dwelling/tabernacle) — the tabernacle term, the mobile sanctuary of the wilderness period now made permanent. <strong>vehayiti lahem le'elohim vehem yihyu li le'am</strong> ('I will be their God and they will be my people'): the covenant formula for the last time in ch 37. The covenant formula appears at the end of the restoration section as the ultimate statement of what YHWH's restoration accomplishes: the covenant relationship fully reconstituted.</p>",
    "28": "<p><strong>veyadu haggoyim ki ani YHWH meqaddesh et-yisrael</strong> ('the nations will know that I am the LORD who sanctifies Israel'): the recognition formula in the chapter's closing verse — but with a new epithet added: <em>meqaddesh et-yisrael</em> ('the one who sanctifies Israel'). YHWH's sanctifying of Israel is the means of his self-disclosure to the nations. The nations learn who YHWH is by watching what he does to Israel: restores, reunifies, gives a Davidic king, places his sanctuary, sanctifies. <strong>bihyot miqdashi betocham le'olam</strong> ('when my sanctuary is in their midst forever'): the sanctuary's permanent presence is the sign that the nations read.</p>"
  },
  "38": {
    "1": "<p>The Gog oracle opens with the standard word-event formula — and then addresses the most mysterious figure in Ezekiel's prophecy. The oracle's placement after chs 36-37 (restoration promises) and before ch 40-48 (the temple vision) situates it as the climactic threat before the final rest: the restored Israel will face a last assault before the permanent sanctuary is established.</p>",
    "2": "<p><strong>ben-adam sim panecha el-Gog eretz Magog nesi rosh Meshech veTuval</strong> ('son of man, set your face toward Gog, the land of Magog, the chief prince of Meshech and Tubal'): <em>Gog</em> (H1463) — the personal name of the eschatological adversary; <em>Magog</em> — the land/people (Gen 10:2, son of Japheth). The genealogical connection to Japheth's descendants locates Gog among the northern peoples. <em>nesi rosh</em> ('chief prince' or 'prince of Rosh') — the title that identifies Gog as the paramount political-military ruler of the northern peoples. Meshech and Tubal reappear from 27:13 and 32:26 (peoples associated with Asia Minor).</p>",
    "3": "<p><strong>hineni elecha Gog</strong> ('I am against you, Gog'): the divine confrontation formula — only YHWH can address the eschatological adversary in the second person. The same formula used against Pharaoh (29:3; 30:22) and the other OAN figures is here directed at the mysterious Gog. The <em>hineni elecha</em> ('I am against you') is the most direct expression of divine opposition in Ezekiel's vocabulary.</p>",
    "4": "<p><strong>veshavti otach venatethi chchachim bilichyeycha</strong> ('I will turn you around and put hooks in your jaws'): the hooks-in-jaws image again — used for Pharaoh in 29:4. YHWH driving the great adversary into position is the theological claim that the Gog invasion is itself part of the divine plan. <em>vetzotzeti otach</em> ('I will lead you out') — YHWH as the one who brings Gog against Israel, making the attack itself the vehicle of divine judgment. <strong>vechal-cheylecha susim uphashim</strong> ('all your army, horses and horsemen'): the great military coalition Gog assembles.</p>",
    "5": "<p>The coalition: <em>Paras</em> (Persia/Iran), <em>Cush</em> (Ethiopia), <em>Put</em> (Libya/North Africa). The same African coalition as appeared in the Egypt oracles (30:5) now assembled under Gog. The eschatological army draws on the same imperial geography as Ezekiel's historical oracles — all the great powers of the known world assembled against restored Israel.</p>",
    "6": "<p><em>Gomer</em> and <em>Beit-Togarma</em> from the northern quarters — the peoples from the far north. Gomer (H1586, Cimmerians in Greek; Gen 10:2-3, son of Japheth); Beth-Togarmah (north of the Euphrates, probably Armenia). The comprehensive directional coverage: south (Persia, Cush, Put) and north (Gomer, Beth-Togarmah) — a global coalition against the tiny restored Israel.</p>",
    "7": "<p><strong>hikkon vehachen lecha atah vekhol-qahalcha haniqhalim alecha</strong> ('be prepared and ready — you and all the company assembled around you'): YHWH addressing Gog as if giving military orders — the ironic military briefing of the adversary whom YHWH is actually positioning for destruction. <em>vehayta lahem lemishmar</em> ('be their guard'): Gog as the guardian/commander of the coalition assembled against Israel.</p>",
    "8": "<p><strong>meyamim rabbim tipaqed</strong> ('after many days you will be called up'): <em>paqad</em> (H6485, attend to/visit/muster — often used for divine inspection or military muster). <strong>beacharit hashanim</strong> ('in the latter years'): <em>acharit hashanim</em> (H319 + H8141, end of years/latter years) — the eschatological time-marker. <strong>tavo el-aretz meshovevet mecherevin niqubbetzet al-harei yisrael</strong> ('you will come against a land restored from the sword, gathered from many peoples, on the mountains of Israel'): the attack is explicitly against the restored Israel of chs 36-37 — the returned exiles in their homeland are the target of the eschatological assault.</p>",
    "9": "<p><strong>vaalita kashoah tavo</strong> ('you will come up like a storm'): <em>shoah</em> (H7722, devastating storm/catastrophe/tempest) — the overwhelming force of the eschatological assault. <strong>keanav lechassot haaretz tihyeh atah vekhol-agafecha</strong> ('like a cloud covering the land you and all your troops'): the storm-cloud imagery for a vast army covering the land. The darkness of the cloud-army against the land of restored Israel is the visible manifestation of the eschatological threat.</p>",
    "10": "<p><strong>veaalah devarim al-levavecha vechashabta machashevet raah</strong> ('thoughts will arise in your mind and you will devise an evil plan'): the interior motivation of Gog is exposed — evil <em>machashevet</em> (H4284, thoughts/devices/plans). The evil plan arises from Gog's own heart, yet it is simultaneously within YHWH's sovereign orchestration (v.4: YHWH puts hooks in Gog's jaws). The dual agency of evil instruments serving divine purposes is sustained throughout these oracles.</p>",
    "11": "<p><strong>veamarta e'eleh el-eretz perazot</strong> ('I will go up against the land of unwalled villages'): <em>perazot</em> (H6519, unwalled/open settlements) — Israel dwelling in security without walls or bars or gates. The vulnerability of the restored Israel is its openness: a people dwelling in safety, no walls, no defenses. The attack on the open villages is the attack on trust in YHWH's protection rather than in military fortification.</p>",
    "12": "<p><strong>livzoz baz ulishlol shalal</strong> ('to plunder and loot'): the double alliteration in Hebrew — <em>baz</em> (H957, plunder) + <em>shalal</em> (H7998, spoil/booty). The economic motivation of the attack: the accumulated wealth of the restored Israel is the target. <strong>al-am mesuphaf mitoch haaratzot</strong> ('on a people gathered from the nations'): the exiles-returned, now wealthy from agricultural restoration (36:29-30), are the economic target. <em>qinyanim veqonyeh</em> ('goods and possessions') — the tangible prosperity of the covenant restoration becomes the bait that draws Gog.</p>",
    "13": "<p>The trading nations — Sheba, Dedan, merchants of Tarshish — question whether Gog is coming to plunder (showing commercial awareness of the attack). These are the same trading nations of 27:20-22 (Ezekiel's Tyre oracle). Their question is not opposition but commercial interest: <em>halasheset baz attah ba?</em> ('have you come to plunder?'). The merchants of the world are watching the eschatological assault with commercial calculation rather than moral horror.</p>",
    "14": "<p><strong>lachen hinabbe ben-adam veamarta leGog</strong> ('therefore prophesy, son of man, and say to Gog'): Ezekiel is commissioned to prophesy directly to Gog — the eschatological adversary as the object of prophetic address, just as historical nations received the OAN oracles. <strong>beyom shevet ami yisrael lavetach halo teda</strong> ('on the day my people Israel dwell in safety, will you not take notice?'): YHWH asking Gog rhetorically — the secure settlement of Israel is both the trigger for Gog's attack and the sign of YHWH's restoration.</p>",
    "15": "<p><strong>ubata mimqomcha miyrektei tzaphon</strong> ('you will come from your place out of the remote parts of the north'): <em>yarktei tzaphon</em> (H3411 + H6828, remote parts/recesses of the north) — the north as the direction of mythic threat (cf. Jer 1:14 'out of the north evil will break out'; Isa 14:13 'mountain of assembly in the far north'). The cosmic north as the direction of the final assault. <strong>ammim rabbim itach</strong> ('many peoples with you'): the vast multinational coalition of vv.5-6.</p>",
    "16": "<p><strong>vaalita al-ami yisrael ke'anan lechassot haaretz</strong> ('you will go up against my people Israel like a cloud covering the land'): the cloud imagery of v.9 repeated — the storm-cloud assault against restored Israel. <strong>beacharit hayamim yihyeh</strong> ('in the latter days it will be'): the eschatological time-marker (<em>acharit hayamim</em>, H319 + H3117) — the time when the present age reaches its completion. <strong>veheveti otcha al-artzi</strong> ('I will bring you against my land'): YHWH explicitly orchestrating Gog's attack against his own land — the assault serves YHWH's purpose of displaying his holiness to the nations. <strong>lemaan deathi haggoyim bi lehiqqdashi vecha Gog leeyneichem</strong> ('so that the nations may know me when I show myself holy through you, Gog').</p>",
    "17": "<p><strong>hata attah hu asher dibberi biyamim qadmonim beyad avadai neviiei yisrael</strong> ('are you the one about whom I spoke in earlier days through my servants the prophets of Israel?'): YHWH's self-referential query — connecting the Gog oracle to earlier prophetic traditions (Isa 14:25-27; Jer 4:5-13; Zeph 3:8). The eschatological adversary was anticipated by earlier prophecy; Ezekiel's oracle is the explicit fulfillment of those earlier references. This verse places the Gog material within the canonical tradition of eschatological judgment.</p>",
    "18": "<p><strong>vehayah bayyom hahu beyyom bo Gog al-admat yisrael</strong> ('on that day, when Gog comes against the land of Israel'): <em>bayyom hahu</em> — the eschatological 'on that day' formula. <strong>yaale chamati vaappi</strong> ('my wrath will flare up'): <em>chemah</em> (H2534, wrath/heat/fury) + <em>ap</em> (H639, nose/anger) — the classic pair of divine anger vocabulary. <em>beqin'ati vebe'esh evrati</em> ('in my jealousy and in the fire of my wrath'): three anger words — <em>qin'ah</em> (jealousy/zeal), <em>chemah</em> (wrath), <em>evrah</em> (H5678, rage/fury) — piled up to convey the intensity of the divine response to the final assault on restored Israel.</p>",
    "19": "<p><strong>vebiqqin'ati vebe'esh evrati dibbari</strong> ('in my jealousy and blazing wrath I declare'): the formal declaration of the eschatological judgment. <strong>im-lo bayyom hahu yihyeh ra'ash gadol al-admat yisrael</strong> ('there will be a great earthquake in the land of Israel on that day'): <em>ra'ash</em> (H7494, earthquake/shaking/commotion) — the cosmic shaking that accompanies YHWH's intervention against Gog. The earthquake is not merely geological but theophanic — YHWH's physical presence disturbing the created order.</p>",
    "20": "<p><strong>vera'ashu mipenai degei hayam veoph hashamayim vechayat hassadeh</strong> ('the fish of the sea, the birds of the sky, and the beasts of the field will tremble before me'): the cosmic trembling extends to the entire animal kingdom — the earthquake disrupts the entire created order. <strong>vekhol-adam asher al-penei haaretz</strong> ('and all the people on the face of the earth'): universal human trembling at the theophany. <strong>veniharsu heharim venaphelu hamaqdshot</strong> ('the mountains will be thrown down and the cliffs will fall'): the topographical disruption — the mountains of Israel that received the restoration promises now shake at the divine self-disclosure.</p>",
    "21": "<p><strong>veqarati alav lekol-harai cherev</strong> ('I will call for a sword against him throughout all my mountains'): YHWH summoning the sword throughout his own land — the mountains of Israel where Gog's forces are deployed become the site of their destruction. <strong>cherev ish beachiv tihyeh</strong> ('every man's sword will be against his brother'): the coalition's internal collapse through friendly fire — the multinational army turns on itself, the confusion of the divine judgment causing fratricide among the allied forces.</p>",
    "22": "<p><strong>venishpatti itto bedever uvdad vegeshem shotef veavaney elgavish</strong> ('I will execute judgment on him with pestilence and bloodshed; I will rain down torrents of rain, hailstones, fire and brimstone'): the five instruments of divine judgment against Gog — pestilence, blood, rain, hail, fire and brimstone. The last two (fire and brimstone) recall Sodom's destruction (Gen 19:24) — the primordial judgment city-destroying event applied to the eschatological adversary. <em>elgavish</em> (H68 + H1378, brimstone/sulfur hailstones) — the specific word for the sulfurous hail of divine judgment.</p>",
    "23": "<p><strong>vehitgaddilti vehitqaddishti venodaati le-eynei goyim rabbim</strong> ('I will show my greatness and my holiness and make myself known in the eyes of many nations'): the recognition formula at maximum scope — not just one nation but <em>goyim rabbim</em> (many nations) will know YHWH through the Gog judgment. <strong>veyadu ki-ani YHWH</strong>: the Ezekielian recognition formula closes the chapter, as it closes every major unit. The entire Gog oracle, like all of Ezekiel's oracles, serves this one epistemological purpose: YHWH's self-disclosure.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'ezekiel')
    merge_comm(existing, EZK_ORIG)
    save_comm('mkt-original', 'ezekiel', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-original/ezekiel.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/ezekiel.json').read_text())

    all_ok = True
    for ch in [36, 37, 38]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
